#include<bits/stdc++.h>
using namespace std;

int n, b, temp, sum, ans;
int lasta[200005];
int nexta[200005];
vector<int> v;

int main() {
	cin >> n >> b;

	for (int i = 1; i <= n; i++) {
		int x;
		cin >> x;
		if (x == b) {
			temp = i-1;
			v.push_back(0);
		} else if (x < b) {
			v.push_back(-1);
		} else {
			v.push_back(1);
		}
	}

	/*for (int i = 0; i < n; i++) {
		cout << v[i] << " ";
	}
	cout << "\n" << temp << "\n";*/
	for (int i = temp; i < n; i++) {
		//cout<<"1";
		sum += v[i];
		nexta[sum + n]++;
		//cout << sum + n << "\n";
	}
	sum = 0;
	//cout << "\n";
	for (int i = temp; i >= 0; i--) {
		//	cout<<"2";
		sum += v[i];
		lasta[sum + n]++;
		//cout << sum + n << "\n";
	}
	for (int i = 0; i <= n * 2; i++) {
		//	cout<<"3";
		if (lasta[i] != 0 && nexta[n * 2 - i] != 0 ) {
			//cout<<4;
			ans += lasta[i] * nexta[n * 2 - i];
		}

	}
	cout << ans;

}
